    public static List<String> getStates() {
        List<String> states = new ArrayList<>(stateToDistricts.keySet());
        java.util.Collections.sort(states);
        return states;
    }

    public static List<String> getDistricts(String state) {
        List<String> districts = stateToDistricts.get(state);
        if (districts == null) return new ArrayList<>();
        List<String> sortedDistricts = new ArrayList<>(districts);
        java.util.Collections.sort(sortedDistricts);
        return sortedDistricts;
    }

    public static List<String> getMarkets(String district) {
        List<String> markets = districtToMarkets.get(district);
        if (markets == null) return Arrays.asList("Local Market", "Regional Mandi");
        return markets;
    }

